import React, { useState, useEffect } from 'react';
import Dashboard from './pages/Dashboard';
import ContactsPage from './pages/ContactsPage';
import ContactDetail from './pages/ContactDetail';
import { getAuthStatus } from './api';
import './App.css';

export default function App() {
  const [page, setPage] = useState('dashboard');
  const [selectedContactId, setSelectedContactId] = useState(null);
  const [gmailConnected, setGmailConnected] = useState(false);

  useEffect(() => {
    // Check URL for OAuth callback result
    const params = new URLSearchParams(window.location.search);
    if (params.get('gmail') === 'connected') {
      setGmailConnected(true);
      window.history.replaceState({}, '', '/');
    }
    checkAuthStatus();
  }, []);

  async function checkAuthStatus() {
    try {
      const res = await getAuthStatus();
      setGmailConnected(res.data.gmailConnected);
    } catch (e) {
      // ignore
    }
  }

  function navigateTo(p, contactId = null) {
    setPage(p);
    if (contactId) setSelectedContactId(contactId);
  }

  return (
    <div className="app">
      <Sidebar page={page} navigateTo={navigateTo} gmailConnected={gmailConnected} />
      <main className="main-content">
        {page === 'dashboard' && <Dashboard navigateTo={navigateTo} />}
        {page === 'contacts' && <ContactsPage navigateTo={navigateTo} />}
        {page === 'contact-detail' && (
          <ContactDetail
            contactId={selectedContactId}
            gmailConnected={gmailConnected}
            navigateTo={navigateTo}
          />
        )}
      </main>
    </div>
  );
}

function Sidebar({ page, navigateTo, gmailConnected }) {
  async function connectGmail() {
    try {
      const res = await fetch('/auth/google/url');
      const data = await res.json();
      window.location.href = data.url;
    } catch (e) {
      alert('Could not start Gmail auth');
    }
  }

  return (
    <aside className="sidebar">
      <div className="sidebar-logo">
        <div className="logo-mark">B</div>
        <div>
          <div className="logo-name">Braind</div>
          <div className="logo-sub">Outreach</div>
        </div>
      </div>

      <nav className="sidebar-nav">
        <button
          className={`nav-item ${page === 'dashboard' ? 'active' : ''}`}
          onClick={() => navigateTo('dashboard')}
        >
          <span className="nav-icon">▦</span>
          Dashboard
        </button>
        <button
          className={`nav-item ${page === 'contacts' || page === 'contact-detail' ? 'active' : ''}`}
          onClick={() => navigateTo('contacts')}
        >
          <span className="nav-icon">◎</span>
          Contacts
        </button>
      </nav>

      <div className="sidebar-bottom">
        <div className={`gmail-status ${gmailConnected ? 'connected' : 'disconnected'}`}>
          <span className="status-dot"></span>
          Gmail {gmailConnected ? 'Connected' : 'Disconnected'}
        </div>
        {!gmailConnected && (
          <button className="btn-connect-gmail" onClick={connectGmail}>
            Connect Gmail
          </button>
        )}
      </div>
    </aside>
  );
}
